    return { success: false, error: "Order must have at least one item", code: "VALIDATION_ERROR" };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return { success: false, error: `Product ${item.productId} not found`, code: "VALIDATION_ERROR" };
    }
    if (item.quantity <= 0) {
      return { success: false, error: "Quantity must be positive", code: "VALIDATION_ERROR" };
    }
    if (product.stock < item.quantity) {
      return { success: false, error: `Insufficient stock for ${product.name}`, code: "VALIDATION_ERROR" };
    }

    product.stock -= item.quantity;
    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);
  return { success: true, data: order };
}

export function updateOrderStatus(id: number, status: string): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    return { success: false, error: "Order not found", code: "NOT_FOUND" };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    return {
      success: false,
      error: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      code: "VALIDATION_ERROR",
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: `Cannot transition from ${order.status} to ${status}`,
      code: "VALIDATION_ERROR",
    };
  }

  order.status = status as typeof order.status;
  return { success: true, data: order };
}
```

#### File 4: `src/routes/products.ts` (MODIFY -- full rewrite)

The route handler becomes a thin HTTP adapter. It parses request parameters, calls the service, and maps results to HTTP responses.

```typescript
import { Router } from "express";
import { getProducts, getProductById, adjustProductStock } from "../services/product-service.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" && !isNaN(parseFloat(minPrice)) ? parseFloat(minPrice) : undefined,
    maxPrice: typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice)) ? parseFloat(maxPrice) : undefined,
  };

  const result = getProducts(filters);
  // getProducts always succeeds, but we use the pattern consistently
  res.json(result.data);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getProductById(id);

  if (!result.success) {
    res.status(result.code === "NOT_FOUND" ? 404 : 400).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  const result = adjustProductStock(id, adjustment);

  if (!result.success) {
    res.status(result.code === "NOT_FOUND" ? 404 : 400).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

export { router as productRouter };
```

**What changed**: All filtering logic, summary computation, stock validation, and computed-field logic is gone. The handler only: (1) extracts and parses request params, (2) calls a service function, (3) maps the result code to an HTTP status code and sends the response.

**What stays the same**: The router structure, export name `productRouter`, route paths, and response shapes are all identical -- so `app.ts` and all tests remain unaffected.

